## TypeScript

```typescript
// Using a type alias
type UserJSON = {
    first_name: string;
    last_name: string;
    email: string;
};

// Map to internal model
interface User {
    firstName: string;
    lastName: string;
    email: string;
}

function fromJSON(data: UserJSON): User {
    return {
        firstName: data.first_name,
        lastName: data.last_name,
        email: data.email,
    };
}
```

### With class-transformer

```typescript
import { Expose, plainToInstance } from "class-transformer";

class User {
    @Expose({ name: "first_name" })
    firstName: string;

    @Expose({ name: "last_name" })
    lastName: string;
}
```

